```python
import os
from collections import Counter

def read_files_in_directory(directory):
    words = []
    for filename in os.listdir(directory):
        if filename.endswith(".txt"):
            file_path = os.path.join(directory, filename)
            with open(file_path, 'r', encoding='utf-8') as file:
                content = file.read()
                words.extend(content.split())
    return words

def count_word_occurrences(words):
    return Counter(words)

def get_top_n_words(word_counts, n=5):
    return word_counts.most_common(n)

def main(directory):
    words = read_files_in_directory(directory)
    word_counts = count_word_occurrences(words)
    top_n_words = get_top_n_words(word_counts)
    print("Top-5 most frequent words:")
    for word, count in top_n_words:
        print(f"{word}: {count}")

if __name__ == "__main__":
    directory = input("Enter the directory path containing text files: ")
    main(directory)
